var findPaths = function(m, n, maxMove, startRow, startColumn) {
    const MOD = 1000000007n;
    let dp = Array.from({length: m}, () => new Array(n).fill(0n));
    dp[startRow][startColumn] = 1n;
    let result = 0n;
    const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];
    for (let step = 0; step < maxMove; step++) {
        const ndp = Array.from({length: m}, () => new Array(n).fill(0n));
        for (let r = 0; r < m; r++) {
            for (let c = 0; c < n; c++) {
                const cur = dp[r][c];
                if (cur === 0n) continue;
                for (const [dr, dc] of dirs) {
                    const nr = r + dr, nc = c + dc;
                    if (nr >= 0 && nr < m && nc >= 0 && nc < n) {
                        ndp[nr][nc] = (ndp[nr][nc] + cur) % MOD;
                    } else {
                        result = (result + cur) % MOD;
                    }
                }
            }
        }
        dp = ndp;
    }
    return Number(result % MOD);
};
